import {PiMath} from "pimath/esm"

const name="fraction"

const description = `fraction,[paramû´tres]

**paramû´tres**
- r=rûˋduit
`
export function FractionChecker(options){
	options = options??[]

	const expectReduced = options.includes("r") || options.includes("reduced")

	return {name, description,
		format: () => {
			let opts = []
			if (expectReduced) {
				opts.push("rûˋduite")
			}

			return `rûˋponse sous forme de fraction ${opts.join(",")}`
		},
		check: (expectedAnswer, answer = []) => {
			// Le rûˋsultat est exactement ce qui est demandûˋ
			if(answer===expectedAnswer){
				return {
					result: true,
					message: ""
				}
			}

			let FAnswer, FExpected

			try{
				FAnswer = new PiMath.Fraction(answer)
				FExpected = new PiMath.Fraction(expectedAnswer)
			}catch{
				return {
					result: false,
					message: "La fraction n'est pas formatûˋe correctement."
				}
			}

			if(FAnswer.isNotEqual(FExpected)){
				return {
					result: false,
					message: "La rûˋponse donnûˋe n'est pas juste."
				}
			}

			if(FAnswer.denominator<0){
				return {
					result: false,
					message: "Le dûˋnominateur doit ûˆtre positif."
				}
			}

			if(!FAnswer.isReduced() && expectReduced){
				return {
					result: false,
					message: "La fraction n'est pas rûˋduite."
				}
			}


			return {
				result: true,
				message: ""
			}
		}
	}

}
