import {ExactChecker} from "@/Composables/Checkers/ExactChecker"
import {stripFirstCharacter, stripLastCharacter} from "@/Composables/checkersConfig"
import {NumberChecker} from "@/Composables/Checkers/NumberChecker"
import {FractionChecker} from "@/Composables/Checkers/FractionChecker"

const name = "coord"
const description = `coord,[paramû´tres]

**paramû´tres**
- nb= les coordonnûˋes sont des nombres
- frac= les coordonnûˋes sont des fractions
`

export function CoordChecker(options) {
	// TODO: coordchecker is by default using exactChecker. Might also be good to use nb checker
	options = options??[]
	let checker
	if(options.includes("nb")){
		checker = NumberChecker()
	}else if(options.includes("frac")){
		checker = FractionChecker()
	}else{
		checker = ExactChecker()
	}

	return {
		name, description,
		format: () => "Coordonnûˋes d'un point sous la forme \\((a;b)\\)",
		check: (expectedAnswer, answer = []) => {
			if (expectedAnswer === answer) {
				return {
					result: true,
					message: ""
				}
			}

			// Manque les parenthû´ses
			if (answer[0] !== "(" || answer[answer.length - 1] !== ")") {
				return {
					result: false,
					message: "des coordonnûˋes commencent et se terminent par des parenthû´ses"
				}
			}

			// On rûˋcupû´re les valeurs
			let values = answer.split(";"),
				expectedValues = expectedAnswer.split(";")

			if (values.length === 1) {
				return {
					result: false,
					message: "des coordonnûˋes ont au moins deux valeurs, sûˋparûˋes par un \\(;\\)"
				}
			}

			if (values.length !== expectedValues.length) {
				return {
					result: false,
					message: "la dimension de la coordonnûˋes ne correspond pas"
				}
			}

			// remove the parentese from the first and last value.
			values[0] = stripFirstCharacter(values[0])
			values[values.length - 1] = stripLastCharacter(values[values.length - 1])

			if (expectedValues[0].startsWith("(")) {
				expectedValues[0] = stripFirstCharacter(expectedValues[0])
			}

			if (expectedValues[expectedValues.length - 1].endsWith(")")) {
				expectedValues[expectedValues.length - 1] = stripLastCharacter(expectedValues[expectedValues.length - 1])
			}


			// let eChecker = ExactChecker(options)
			for (let i = 0; i < values.length; i++) {
				let result = checker.check(expectedValues[i], values[i])
				if (!result.result) {
					return {
						result: false,
						message: `la ${i === 0 ? "1û´re" : (i + 1) + "û´me"} coordonnûˋe n'est pas juste.<br>${result.message}`
					}
				}
			}

			// tous les tests sont passûˋs ! La rûˋponse est donc juste
			return {
				result: true,
				message: ""
			}
		}
	}
}
