import {NumberChecker} from "@/Composables/Checkers/NumberChecker"

const name = "scientific"
const description = `scientific|scn,[paramû´tres]

//TODO: scn: mode stricte
**paramû´tres**
- [1,2,3,4,...]: nombre de chiffre aprû´s la virgule
- s: strict (1.2 ne passe pas pour 1.20)
`
export function ScientificChecker(options) {
	options = options ?? []

	return {
		name, description,
		format: () => {
			if (isNaN(options[0])) {
				return "rûˋponse en notation scientifique"
			} else {
				return `rûˋponse en notation scientifique û  ${options[0]} chiffre(s) significatif(s)`
			}
		},
		check: (expectedAnswer, answer = []) => {
			// Le rûˋsultat est exactement ce qui est demandûˋ
			if (answer.toString() === expectedAnswer.toString()) {
				return {
					result: true,
					message: ""
				}
			}

			// On vûˋrifie que le format est bien de type scientifique.
			const PS = +(answer.split("*")[0]),
				OG = +(answer.split("10^")[1] || 0),
				ePS = +(expectedAnswer.split("*")[0]),
				eOG = +(expectedAnswer.split("10^")[1] || 0)

			if (!answer.includes("*10^")) {
				return {
					result: false,
					message: "le format de rûˋponse n'est pas une notation scientifique."
				}
			}

			// On vûˋrifie la partie significative
			if (PS < 1 || PS >= 10) {
				return {
					result: false,
					message: "la partie significative n'est pas entre 1 et 10 (non compris)"
				}
			}

			if (PS !== ePS) {
				return {
					result: false,
					message: "erreur dans la partie significative: " + new NumberChecker(options).check(ePS, PS).message
				}
			}


			// On vûˋrifie l'ordre de grandeur.
			if (OG !== eOG) {
				return {
					result: false,
					message: "l'ordre de grandeur n'est pas juste.."
				}
			}


			// Il n'y a pas d'option -> le rûˋsultat ne peut pas ûˆtre validûˋ.
			if (options.length === 0) {
				return {
					result: false,
					message: " ? "
				}
			}

			// Nombre de dûˋcimales souhaitûˋes
			const nbDecimales = +options[0]
			// Nomber de dûˋcimale de la rûˋponse
			let crtDecimales = answer.toString().split(".")

			// Le nombre de chiffres aprû´s la virgule n'est pas juste
			if (crtDecimales.length === 1 || crtDecimales[1].length !== nbDecimales) {
				return {
					result: false,
					message: `Il faut ${nbDecimales} chiffre(s) aprû´s la virgule.`
				}
			}

			// Le dernier chiffre n'est pas juste - il s'agit peut ûˆtre d'un problû´me d'arrondi ?
			if (crtDecimales[crtDecimales.length - 1] - expectedAnswer.toString()[expectedAnswer.toString().length - 1] === 1) {
				return {
					result: false,
					message: "Peut ûˆtre un problû´me d'arrondi ?"
				}
			}
		}

	}

}
