import {splitAtSigns, splitIfOutsideParentheses} from "@/helpers/helperFunctions"

const name = "exp"
const description = `exp,[paramû´tres]

**paramû´tres**
aucun
`

export function ExpChecker(options) {
	options = options ?? []

	return {
		name, description,
		format: () => {
			return "polynûÇme avec des exponentielles"
		},
		check: (expectedAnswer, answer = []) => {
			// Le rûˋsultat est exactement ce qui est demandûˋ
			const stringAnswer = answer.toString(),
				asciiAnswer = stringAnswer.startsWith("#") ? stringAnswer.substring(1) : stringAnswer

			if (asciiAnswer === expectedAnswer.toString()) {
				return {
					result: true,
					message: ""
				}
			}

			// plusieurs possible:
			// ae^(polynom)
			// ae^(polynom) + be^(polynom)
			// ae^(polynom) + be^(polynom) / ae^(polynom) + be^(polynom)

			// on coupe en numûˋrateur / dûˋnominateur
			// on recherche un endroit qui n'est pas entre parenthû´se.
			let [N, D] = splitIfOutsideParentheses(answer),
				[eN, eD] = splitIfOutsideParentheses(expectedAnswer)

			if(D===undefined && eD !== undefined){
				return {
					result: false,
					message: "Un dûˋnominateur est attendu..."
				}
			}

			if(D!==undefined && eD === undefined){
				return {
					result: false,
					message: "Aucun dûˋnominateur n'est prûˋvu dans cette rûˋponse."
				}
			}

			const resultatNumerateur = expCompare(eN, N)

			if(!resultatNumerateur.result)return resultatNumerateur

			// On contrûÇle les dûˋnominateurs
			if(D!==undefined && eD !== undefined){
				return expCompare(eD, D)
			}

			return {
				result: true,
				message: ""
			}
		}
	}
}

function expCompare(eValue, value){
	// On contrûÇle maintenant les numûˋrateurs
	let elements_N = splitAtSigns(value),
		elements_eN = splitAtSigns(eValue)
	if(elements_eN.length!==elements_N.length){
		return {
			result: false,
			message: "il n'y a pas le bon nombre d'ûˋlûˋments au numûˋrateur"
		}
	}

	// Chaque ûˋlûˋment est maintenant de la forme
	// (polynom)e^(polynom)
	let missing_N = []
	elements_N.forEach((element, index) => {
		if(elements_eN.includes(element)){
			elements_eN = elements_eN.splice(index, 1)
		}
	})

	if(elements_eN.length>0){
		// Il faut encore contrûÇler chaque morceau comme des polynûÇmes rationnels.
		// TODO: exp : on doit contrûÇler que (polynom)e^(polynom) peut ûˆtre formatûˋ diffûˋremment
		const cnt = elements_eN.length
		return {
			result: false,
			message: `Il y a ${cnt} ûˋlûˋment${cnt===1?"":"s"} qui ${cnt===1?"est":"sont"} faux.`
		}
	}

	return {
		result: true,
		message: ""
	}
}
