import {PiMath} from "pimath/esm"

const name = "polynom"
const description = `polynom,[paramû´tres]

**paramû´tres**
- f=factorisûˋ
- F=entiû´rement factorisûˋ \\((2x+4)(x-3)\\) ne passe pas.
- d=dûˋveloppûˋ
`

export function PolynomChecker(options) {
	options = options ?? []

	return {name, description,
		format: () => {
			let opts = []

			if (options.includes("f") || options.includes("factors")) {
				opts.push("factorisûˋ")
			} else if (options.includes("F") || options.includes("FACTORS")) {
				opts.push("entiû´rement factorisûˋ")
			} else if (options.includes("d") || options.includes("develop")) {
				opts.push("dûˋveloppûˋ")
			}

			return `polynûÇme ${opts.join(", ")}`
		},
		check: (expectedAnswer, answer) => {
			// Make sur the polynom is constructable
			let A, Q

			try{
				A = new PiMath.Polynom(answer)
				Q = new PiMath.Polynom(expectedAnswer)
			}catch{
				return {
					result: false,
					message: "Le polynûÇme n'est pas formûˋ correctement."
				}
			}



			// Polynom must be equals.
			if (!Q.isEqual(A)) {
				return {
					result: false,
					message: "Le polynûÇme n'est pas le mûˆme."
				}
			}

			/** Polynom checker options */
			// Factorized
			if (options.includes("f") || options.includes("factor") || options.includes("F") || options.includes("FACTORS")) {
				try {
					if (!A.isFactorized(answer, options.includes("f") || options.includes("factor"))) {
						return {
							result: false,
							message: "Le polynûÇme n'est pas (entiû´rement) factorisûˋ."
						}
					}
				} catch {
					return {
						result: false,
						message: "Le polynûÇme n'est pas (entiû´rement) factorisûˋ."
					}
				}
			}

			// Developed
			if (options.includes("d") || options.includes("develop")) {
				if (!A.isDeveloped(answer)) {
					return {
						result: false,
						message: "Le polynûÇme n'est pas (entiû´rement) dûˋveloppûˋ."
					}
				}
			}

			// Reduced
			if (options.includes("r") || options.includes("reduced")) {
				// if(!Q.isReduced(answer)){
				// 	return {
				// 		result: false,
				// 		message: "Le polynûÇme n'est pas (entiû´rement) rûˋduit."
				// 	}
				//
				// }
			}

			// If all tests passes, it is correct !
			return {
				result: true,
				message: ""
			}
		}
	}
}
